'use strict';(function(){const indexCfg={cache:true};indexCfg.doc={id:'id',field:['title','content'],store:['title','href'],};const index=FlexSearch.create('balance',indexCfg);window.bookSearchIndex=index;index.add({'id':0,'href':'/docs/tools/','title':"Tools",'content':"Tools Tools に関する情報をまとめる。\n"});index.add({'id':1,'href':'/docs/uncategorized/','title':"Uncategorized",'content':"Uncategorized まだ分類されていない（分類するのが面倒で、後回しになっている）ものです。\n"});index.add({'id':2,'href':'/docs/tools/hugo/','title':"hugo",'content':"hugo hugo に関するページ\n"});index.add({'id':3,'href':'/docs/tools/ide/','title':"IDE",'content':"IDE IDE に関する情報をまとめる。\n"});index.add({'id':4,'href':'/docs/tools/inkdrop/','title':"inkdrop",'content':"Inkdrop とは Markdown でメモが書けるアプリ。\nPlugin があり、カスタマイズが可能。 Inkdrop - Plugins\nInkdrop のプラグインをインストールする 手順は Windows で実施。 他の環境でも ipm コマンドのパスが通っていればいいはず。\nPowerShell を開き、Inkdrop にパスを通す。あとは、プラグインの名前を指定してインストールするだけ。\nPS C:\\\u0026gt; $Env:Path += ';' + $env:LOCALAPPDATA + '\\inkdrop\\bin' PS C:\\\u0026gt; ipm PS C:\\\u0026gt; ipm install vim "});index.add({'id':5,'href':'/posts/','title':"Blog",'content':""});index.add({'id':6,'href':'/posts/first-article/','title':"First Article",'content':"tk3.github.io を作成してから初めてのブログ。\n以前からブログのようにその日に書き残すようなものではなく、文章を書きためたり、その文書を更新していけるようにしたいと考えていた。ブログでも過去の記事を更新すれば良さそうだが、それではブログぽさがない。やはり文書を残すサイトという感じにしたかった。\nちなみにこのサイトは GitHub Actions で Github Pages にデプロイしている。 どこにホスティングしようか迷ったが、簡単にできる Github Pages を選択した。もしかしたら、 tk3.dev の方に移すかもしれない。\n"});index.add({'id':7,'href':'/docs/','title':"Docs",'content':""});})();